    AppIcon.SEARCH -> "ic_search_40dp"
    AppIcon.PUZZLE -> "ic_puzzle"
    AppIcon.IDEA -> "ic_idea"
    AppIcon.BOOKMARK -> "ic_bookmark_black_24dp"
    AppIcon.BOOKMARK_BORDER -> "ic_bookmark_border_black_24dp"
